import { Extension, ToolContext } from '@mariozechner/pi-coding-agent';
import { isToolCallEventType } from '@mariozechner/pi-coding-agent';
import { tool } from 'ai';

// Known extensions in the extensions/ directory
const AVAILABLE_EXTENSIONS = new Set([
  'theme-cycler.ts',
  'focus.ts',
  'agent-team.ts',
  'agent-chain.ts',
  'browser.ts',
]);

export function extension(): Extension {
  return {
    load(context) {
      // Listen for tool call events
      if (isToolCallEventType(context.event)) {
        handleToolRequest(context);
      }
    },
    registerTool: {
      async registerTool(context: ToolContext, name: string, description: string, parameters: Record<string, unknown>) {
        // Dynamic extension loading tool
        const dynamicLoad = tool({
          name: 'dynamic-load-extension',
          description: 'Dynamically load an extension when mentioned. Supported: theme, focus, agent-team, agent-chain.',
          parameters: {
            name: {
              type: 'object',
              properties: {
                identifier: { type: 'string', description: 'Extension identifier (e.g., theme, focus)' },
              },
              required: ['identifier'],
            },
          },
          execute: async ({ identifier }) => {
            const extFile = `extensions/${identifier}.ts`;
            const command = `pi -e ${extFile}`;
            return `Loaded extension: \`${identifier}\``;
          },
        });

        return context.registerTool(name, description, parameters, dynamicLoad);
      },
    },
  };
}

function handleToolRequest(context: ToolContext) {
  const { message, event } = context;
  const extName = message.content.find(c => c.type === 'text')?.text?.split(' ').pop()?.trim();

  if (extName && AVAILABLE_EXTENSIONS.has(extName)) {
    console.log(`[PI] Loading extension: ${extName}`);
    // Return appropriate response
  }
}
